protected boolean sessConnected = false;

public boolean isConnected() {
	return( sessConnected );
}

public boolean connect() {
	if( sessConnected ) {
		return( false );
	}
	else {
		sessConnected = true;
		tranOpen = false;
		return( true );
	}
}

public boolean connect( String username, String password ) {
	final String S_ProcName = "connect";
	if( ( username == null ) || ( username.length() <= 0 ) ) {
		throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			1,
			"username" );
	}
	if( password == null ) {
		throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			2,
			"password" );
	}
	if( ! username.equals( "system" ) ) {
		throw new CFLibRuntimeException( getClass(),
			S_ProcName,
			"Only 'system' is authorized to use a RAM database" );
	}
	if( sessConnected ) {
		return( false );
	}
	else {
		sessConnected = true;
		tranOpen = false;
		return( true );
	}
}

public boolean connect( String loginId, String password, String clusterName, String tenantName ) {
	final String S_ProcName = "connect";
	if( ( loginId == null ) || ( loginId.length() <= 0 ) ) {
		throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			1,
			"loginId" );
	}
	if( password == null ) {
		throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			2,
			"password" );
	}
	if( clusterName == null ) {
		throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			3,
			"clusterName" );
	}
	if( tenantName == null ) {
		throw new CFLibNullArgumentException( getClass(),
			S_ProcName,
			4,
			"tenantName" );
	}
	if( ! loginId.equals( "system" ) ) {
		throw new CFLibRuntimeException( getClass(),
			S_ProcName,
			"Only 'system' is authorized to use a RAM database" );
	}
	if( ! clusterName.equals( "system" ) ) {
		throw new CFLibRuntimeException( getClass(),
			S_ProcName,
			"Only the 'system' Cluster is authorized to use a RAM database" );
	}
	if( ! tenantName.equals( "system" ) ) {
		throw new CFLibRuntimeException( getClass(),
			S_ProcName,
			"Only the 'system' Tenant is authorized to use a RAM database" );
	}
	if( sessConnected ) {
		return( false );
	}
	else {
		sessConnected = true;
		tranOpen = false;
		return( true );
	}
}

public void disconnect( boolean doCommit ) {
	tranOpen = false;
	sessConnected = false;
}

//	Transactions are not supported, so pretend there is always one open

protected boolean tranOpen = false;

public boolean isTransactionOpen() {
	return( tranOpen );
}

public boolean beginTransaction() {
	if( tranOpen ) {
		return( false );
	}
	tranOpen = true;
	return( true );
}

public void commit() {
	tranOpen = false;
}

public void rollback() {
	tranOpen = false;
}

